/**
 * @file  example_card_list.c
 * @brief Demonstrates gui_card_list: a 3-D perspective carousel widget.
 *
 * A single card list is created (orientation selected by
 * CARD_LIST_DEMO_ORIENTATION).  Each card shows a palette colour with a
 * number-digit image overlay.  Two navigation buttons allow manual
 * prev/next stepping.
 *
 * On platforms without a touch screen an optional timer-driven auto-scroll
 * is compiled in (CARD_LIST_AUTO_SCROLL=1) so the carousel cycles
 * automatically every CARD_LIST_AUTO_SCROLL_INTERVAL_MS milliseconds.
 *
 * Widget tree
 * -----------
 *   root
 *   +-- gui_card_list  "cards"      (the carousel)
 *   |   +-- slot[0..N-1]            (managed internally; populated by card_design)
 *   +-- gui_win        "btn_prev"   (previous-card button)
 *   |   +-- gui_rect   "prev_bg"
 *   +-- gui_win        "btn_next"   (next-card button)
 *       +-- gui_rect   "next_bg"
 */

